import { NextResponse } from "next/server";
import path from "path";
import fs from "fs";
import { writeFile } from "fs/promises";
import Tesseract from "node-tesseract-ocr";
import { convert } from "pdf-img-convert"; // Fix import

const uploadDir = path.join(process.cwd(), "public/uploads");

if (!fs.existsSync(uploadDir)) {
  fs.mkdirSync(uploadDir, { recursive: true });
}

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const file = formData.get("file") as File;

    if (!file) {
      return NextResponse.json({ error: "No file uploaded" }, { status: 400 });
    }

    if (!file.name.toLowerCase().endsWith(".pdf")) {
      return NextResponse.json(
        { error: "File must be a PDF" },
        { status: 400 }
      );
    }

    // Save PDF
    const fileName = `${Date.now()}-${file.name.replace(/\s+/g, "_")}`;
    const filePath = path.join(uploadDir, fileName);
    const bytes = await file.arrayBuffer();
    const buffer = Buffer.from(bytes);
    await writeFile(filePath, buffer);

    // Convert PDF to Images
    const images = await convert(filePath, { scale: 2 });

    if (!images.length) {
      return NextResponse.json(
        { error: "Failed to convert PDF to images" },
        { status: 500 }
      );
    }

    let extractedText = "";

    for (const img of images) {
      const tempImagePath = `${filePath.replace(".pdf", "")}.png`;
      await writeFile(tempImagePath, img);

      const text = await Tesseract.recognize(tempImagePath, {
        lang: "eng",
        oem: 1,
        psm: 3,
        tessdataDir: "/path-to-tessdata", // Optional: Specify the correct Tesseract data path
      });


      extractedText += text + "\n";
      fs.unlinkSync(tempImagePath); // Remove temporary image
    }

    return NextResponse.json({ text: extractedText }, { status: 200 });
  } catch (error) {
    console.error("OCR Extraction Error:", error);
    return NextResponse.json(
      { error: "Failed to extract text from PDF" },
      { status: 500 }
    );
  }
}
